import{_ as a,c as s,o as t,ae as n}from"./chunks/framework.Cd-3tpCq.js";const g=JSON.parse('{"title":"Étape 6.2 — Utiliser les Patterns sur plusieurs pages","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/patterns-use.md","filePath":"drupal-canvas/patterns-use.md"}'),r={name:"drupal-canvas/patterns-use.md"};function i(l,e,o,p,u,c){return t(),s("div",null,e[0]||(e[0]=[n(`<h1 id="etape-6-2-—-utiliser-les-patterns-sur-plusieurs-pages" tabindex="-1">Étape 6.2 — Utiliser les Patterns sur plusieurs pages <a class="header-anchor" href="#etape-6-2-—-utiliser-les-patterns-sur-plusieurs-pages" aria-label="Permalink to &quot;Étape 6.2 — Utiliser les Patterns sur plusieurs pages&quot;">​</a></h1><h2 id="utiliser-un-pattern-existant" tabindex="-1">Utiliser un Pattern existant <a class="header-anchor" href="#utiliser-un-pattern-existant" aria-label="Permalink to &quot;Utiliser un Pattern existant&quot;">​</a></h2><p>Maintenant que vous avez créé des Patterns, voyons comment les utiliser efficacement pour construire de nouvelles pages rapidement.</p><h3 id="inserer-un-pattern-dans-une-canvas-page" tabindex="-1">Insérer un Pattern dans une Canvas Page <a class="header-anchor" href="#inserer-un-pattern-dans-une-canvas-page" aria-label="Permalink to &quot;Insérer un Pattern dans une Canvas Page&quot;">​</a></h3><ol><li>Ouvrez une Canvas Page dans l&#39;éditeur</li><li>Dans le <strong>panneau de gauche</strong>, cliquez sur l&#39;onglet <strong>Patterns</strong></li><li>Parcourez les catégories ou utilisez la recherche</li><li>Cliquez ou glissez-déposez le Pattern dans la zone centrale</li></ol><p>Le Pattern est inséré avec <strong>toute sa structure</strong> : sections, composants et leurs configurations.</p><h3 id="personnaliser-le-pattern-apres-insertion" tabindex="-1">Personnaliser le Pattern après insertion <a class="header-anchor" href="#personnaliser-le-pattern-apres-insertion" aria-label="Permalink to &quot;Personnaliser le Pattern après insertion&quot;">​</a></h3><p>Une fois inséré, le Pattern devient une <strong>copie indépendante</strong> sur votre page. Vous pouvez :</p><ul><li>Modifier les textes dans chaque Card</li><li>Changer les images</li><li>Ajouter ou supprimer des éléments</li><li>Modifier les props de chaque composant</li></ul><p>Ces modifications n&#39;affectent <strong>pas</strong> le Pattern original ni les autres pages.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pattern &quot;Section Services&quot; (bibliothèque)</span></span>
<span class="line"><span>        ↓ insertion</span></span>
<span class="line"><span>Copie sur Page &quot;À propos&quot; → modifiable indépendamment</span></span>
<span class="line"><span>Copie sur Page &quot;Accueil&quot;  → modifiable indépendamment</span></span></code></pre></div><h2 id="flux-de-travail-recommande" tabindex="-1">Flux de travail recommandé <a class="header-anchor" href="#flux-de-travail-recommande" aria-label="Permalink to &quot;Flux de travail recommandé&quot;">​</a></h2><h3 id="pour-construire-un-site-complet-avec-canvas" tabindex="-1">Pour construire un site complet avec Canvas <a class="header-anchor" href="#pour-construire-un-site-complet-avec-canvas" aria-label="Permalink to &quot;Pour construire un site complet avec Canvas&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Créez vos composants SDC (Module 3)</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>2. Assemblez Header + Footer (Module 4)</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>3. Construisez la page d&#39;accueil (Module 5)</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>4. Sauvegardez les sections récurrentes comme Patterns</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>5. Construisez les autres pages en utilisant les Patterns</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>6. Personnalisez le contenu de chaque page</span></span></code></pre></div><h3 id="exemple-concret" tabindex="-1">Exemple concret <a class="header-anchor" href="#exemple-concret" aria-label="Permalink to &quot;Exemple concret&quot;">​</a></h3><p>Vous avez construit la page d&#39;accueil avec :</p><ul><li>Section Hero</li><li>Section Services (Grid 3 Cards)</li><li>Section CTA</li></ul><p>Vous voulez maintenant créer la page &quot;Services&quot; :</p><ol><li>Créez une nouvelle Canvas Page <code>Services</code></li><li>Insérez le Pattern <strong>Page intérieure</strong> (Page Header + sidebar)</li><li>Insérez le Pattern <strong>Section Services</strong> en bas de page</li><li>Personnalisez le contenu pour les services détaillés</li></ol><p>En 5 minutes, la page &quot;Services&quot; a une structure complète et cohérente.</p><h2 id="organiser-sa-bibliotheque-de-patterns" tabindex="-1">Organiser sa bibliothèque de Patterns <a class="header-anchor" href="#organiser-sa-bibliotheque-de-patterns" aria-label="Permalink to &quot;Organiser sa bibliothèque de Patterns&quot;">​</a></h2><p>Prenez le temps d&#39;organiser vos Patterns par catégories pour une meilleure productivité :</p><table tabindex="0"><thead><tr><th>Catégorie</th><th>Patterns inclus</th></tr></thead><tbody><tr><td><strong>Héros</strong></td><td>Hero pleine largeur, Hero centré, Hero mini</td></tr><tr><td><strong>Sections</strong></td><td>Services 3 col, Équipe 4 col, Témoignages, À propos</td></tr><tr><td><strong>Pages</strong></td><td>Page intérieure, Page contact, Landing page</td></tr><tr><td><strong>CTAs</strong></td><td>CTA Banner, CTA avec image, CTA footer</td></tr></tbody></table><h2 id="patterns-vs-pages-completes" tabindex="-1">Patterns vs Pages complètes <a class="header-anchor" href="#patterns-vs-pages-completes" aria-label="Permalink to &quot;Patterns vs Pages complètes&quot;">​</a></h2><p>Pour les pages très standardisées (ex: toutes les pages de services ont exactement la même structure), vous pouvez créer un Pattern qui représente <strong>la page entière</strong> :</p><ol><li>Construisez la page complète (Header exclu, car c&#39;est un Global Component)</li><li>Sélectionnez toutes les sections</li><li>Sauvegardez comme Pattern &quot;Page Service Standard&quot;</li></ol><p>Chaque nouvelle page de service utilise ce Pattern et vous n&#39;avez plus qu&#39;à changer les textes.</p><div class="tip custom-block"><p class="custom-block-title">Gain de temps</p><p>Avec une bibliothèque de 8 à 10 Patterns bien conçus, vous pouvez créer une nouvelle page en <strong>moins de 10 minutes</strong>, tout en maintenant une cohérence visuelle parfaite sur l&#39;ensemble du site.</p></div>`,28)]))}const h=a(r,[["render",i]]);export{g as __pageData,h as default};
